// ServiceServerInfo.Validate if the designated constraints aren't met.
type ServiceServerInfoValidationError struct {
	field  string
	reason string
	cause  error
	key    bool
}

// Field function returns field value.
func (e ServiceServerInfoValidationError) Field() string { return e.field }

// Reason function returns reason value.
func (e ServiceServerInfoValidationError) Reason() string { return e.reason }

// Cause function returns cause value.
func (e ServiceServerInfoValidationError) Cause() error { return e.cause }

// Key function returns key value.
func (e ServiceServerInfoValidationError) Key() bool { return e.key }

// ErrorName returns error name.
func (e ServiceServerInfoValidationError) ErrorName() string {
	return "ServiceServerInfoValidationError"
}

// Error satisfies the builtin error interface
func (e ServiceServerInfoValidationError) Error() string {
	cause := ""
	if e.cause != nil {
		cause = fmt.Sprintf(" | caused by: %v", e.cause)
	}

	key := ""
	if e.key {
		key = "key for "
	}

	return fmt.Sprintf(
		"invalid %sServiceServerInfo.%s: %s%s",
		key,
		e.field,
		e.reason,
		cause)
}

var _ error = ServiceServerInfoValidationError{}

var _ interface {
	Field() string
	Reason() string
	Key() bool
	Cause() error
	ErrorName() string
} = ServiceServerInfoValidationError{}
